/**
 * Sanitize value for safe sheet storage (prevent formula injection)
 * @param {*} value - User-provided value
 * @return {*} Safe value (string prefixed with ' if starts with formula char)
 */
function sanitizeForSheet_(value) {
  if (typeof value !== 'string') return value;
  if (/^[=+\-@]/.test(value)) return "'" + value;
  return value;
}

