function checkRateLimit_(action, userEmail) {
  const key = 'rate_' + action + '_' + md5Hash_(userEmail);
  const count = Number(CacheService.getScriptCache().get(key) || '0');
  const limit = RATE_LIMITS[action] || RATE_LIMITS.default;
  if (count >= limit.max) throw new Error('Rate limit exceeded: ' + action);
  CacheService.getScriptCache().put(key, String(count + 1), limit.windowMs / 1000);
}

